CREATE TABLE departments (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT
);

CREATE TABLE employees (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT,
    department_id INTEGER,
    salary REAL
);

INSERT INTO departments (name) VALUES
    ('Yazilim'), ('Pazarlama'), ('Insan Kaynaklari');

INSERT INTO employees (name, department_id, salary) VALUES
    ('Ahmet', 1, 25000),
    ('Ayse', 1, 28000),
    ('Mehmet', 2, 22000),
    ('Zeynep', 3, 20000),
    ('Can', 2, 18000);

-- Ortalama maastan fazla kazanan calisanlar
SELECT name, salary
FROM employees
WHERE salary > (SELECT AVG(salary) FROM employees);

-- IN ile alt sorgu: belirli departmandaki calisanlar
SELECT name
FROM employees
WHERE department_id IN (
    SELECT id FROM departments WHERE name = 'Yazilim'
);

-- EXISTS ile alt sorgu
SELECT name
FROM departments d
WHERE EXISTS (
    SELECT 1 FROM employees e WHERE e.department_id = d.id
);

-- Alt sorguyu FROM icinde kullanma (derived table)
SELECT department_id, avg_salary
FROM (
    SELECT department_id, AVG(salary) AS avg_salary
    FROM employees
    GROUP BY department_id
) AS dept_avg
WHERE avg_salary > 20000;

-- Korelasyonlu alt sorgu: her departmandaki en yuksek maasli kisi
SELECT name, salary, department_id
FROM employees e1
WHERE salary = (
    SELECT MAX(salary) FROM employees e2
    WHERE e2.department_id = e1.department_id
);
